@Model class Note: Identifiable {
    @Attribute(.unique) var id: UUID = UUID()
    var title: String
    var content: String
    var lastModified: Date
    init(title: String, content: String) {
        self.title = title
        self.content = content
        self.lastModified = .now
    }
}

struct NoteApp: App {
    var body: some Scene {
        WindowGroup {
            ContentView()
                .modelContainer(for: Note.self, cloudKitDatabase: .private(

