    var title: String
    var category: Category
}

struct Migration: ModelMigration {
    static func migrate(from old: TaskV1, to new: Task, context: ModelMigrationContext) {
        let cat = context.fetchOrCreate(Category.self, uniqueKey: old.category) {
            Category(name: old.category, color: "gray")
        }
