import SwiftData
import CloudKit

@Model class Project: Identifiable {
    @Attribute(.unique) var id: UUID = UUID()
    var name: String
    var details: String
}

struct ProjectShareView: View {
    @Environment(\.modelContext) private var context
    @Query var projects: [Project]
    @State private var share: CKShare?
    @State private var controller: UICloudSharingController?
    var body: some View {
        List(projects) { project in
            Button("Share") {
                let share = try? context.share(project)
                self.share = share
                if let share = share {
                    let controller = UICloudSharingController(share: share, container: CKContainer.default())
                    controller.availablePermissions = [.allowReadWrite, .allowPrivate] 
                    self.controller = controller
                    UIApplication.shared.windows.first?.rootViewController?.present(controller, animated: true)
                }
            }
        }
    }
}

import SwiftData

// v1
@Model class Person {
    var name: String
    var email: String
}
@Model class Contact {
    var fullName: String
    var email: String
}
// v2
@Model class User {
    var name: String
    var email: String
}

struct MergeMigration: ModelMigration {
    static func migrate(context: ModelMigrationContext) {
        let allPeople = context.fetchAll(Person.self)
        let allContacts = context.fetchAll(Contact.self)
        var seenEmails = Set<String>()
        for person in allPeople {
            if !seenEmails.contains(person.email) {
                let user = User(name: person.name, email: person.email)
                context.insert(user)
                seenEmails.insert(person.email)
            }
        }
        for contact in allContacts {
            if !seenEmails.contains(contact.email) {
                let user = User(name: contact.fullName, email: contact.email)
                context.insert(user)
                seenEmails.insert(contact.email)
            }
        }
    }
}

