import SwiftData

// v1
@Model class PersonV1 {
    var fullName: String
}
// v2
@Model class Person {
    var firstName: String
    var lastName: String
}

struct NameSplitMigration: ModelMigration {
    static func migrate(from old: PersonV1, to new: Person, context: ModelMigrationContext) {
        let parts = old.fullName.split(separator: " ", maxSplits: 1, omittingEmptySubsequences: true)
        new.firstName = parts.first.map(String.init) ?? ""
        new.lastName = parts.dropFirst().first.map(String.init) ?? ""
    }
}

